export interface User {
  id: string;
  username: string;
  email: string;
  phone?: string;
  language: 'en' | 'sv' | 'es' | 'fr';
}

export interface Dish {
  name: string;
  description: string;
  price: number;
}

export interface Restaurant {
  id: string;
  name: string;
  address: string;
  phone: string;
  email: string;
  type: string;
  averagePrice: number;
  description: string;
  picture: string;
  menu: Dish[];
  latitude: number;
  longitude: number;
  website: string;
  distance?: number;
}

export interface SearchFilters {
  priceMin?: number;
  priceMax?: number;
  distanceMin?: number;
  distanceMax?: number;
  type?: string;
  dish?: string;
  freeText?: string;
}

export type ViewMode = 'list' | 'map';
export type SortOption = 'price' | 'distance' | 'type' | 'dish' | 'name';
export type SortOrder = 'asc' | 'desc';

import { createContext, useContext, useState, ReactNode } from 'react';
import { User, Restaurant, SearchFilters, ViewMode, SortOption, SortOrder } from '../types';
import { mockUser, mockRestaurants } from '../data';

interface AppContextType {
  user: User | null;
  setUser: (user: User | null) => void;
  isLoggedIn: boolean;
  restaurants: Restaurant[];
  filteredRestaurants: Restaurant[];
  filters: SearchFilters;
  setFilters: (filters: SearchFilters) => void;
  viewMode: ViewMode;
  setViewMode: (mode: ViewMode) => void;
  sortOption: SortOption;
  setSortOption: (option: SortOption) => void;
  sortOrder: SortOrder;
  setSortOrder: (order: SortOrder) => void;
  selectedRestaurant: Restaurant | null;
  setSelectedRestaurant: (restaurant: Restaurant | null) => void;
  currentPage: string;
  setCurrentPage: (page: string) => void;
  login: (username: string, password: string) => boolean;
  logout: () => void;
  register: (username: string, email: string, password: string) => boolean;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export function AppProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<User | null>(mockUser);
  const [filters, setFilters] = useState<SearchFilters>({});
  const [viewMode, setViewMode] = useState<ViewMode>('map');
  const [sortOption, setSortOption] = useState<SortOption>('distance');
  const [sortOrder, setSortOrder] = useState<SortOrder>('asc');
  const [selectedRestaurant, setSelectedRestaurant] = useState<Restaurant | null>(null);
  const [currentPage, setCurrentPage] = useState('search');

  const filteredRestaurants = mockRestaurants
    .filter((r) => {
      if (filters.priceMin && r.averagePrice < filters.priceMin) return false;
      if (filters.priceMax && r.averagePrice > filters.priceMax) return false;
      if (filters.distanceMax && r.distance && r.distance > filters.distanceMax) return false;
      if (filters.type && r.type !== filters.type) return false;
      if (filters.dish && !r.menu.some((d) => d.name.toLowerCase().includes(filters.dish!.toLowerCase()))) return false;
      if (filters.freeText) {
        const search = filters.freeText.toLowerCase();
        return (
          r.name.toLowerCase().includes(search) ||
          r.description.toLowerCase().includes(search) ||
          r.address.toLowerCase().includes(search) ||
          r.type.toLowerCase().includes(search) ||
          r.menu.some((d) => d.name.toLowerCase().includes(search))
        );
      }
      return true;
    })
    .sort((a, b) => {
      let comparison = 0;
      switch (sortOption) {
        case 'price':
          comparison = a.averagePrice - b.averagePrice;
          break;
        case 'distance':
          comparison = (a.distance || 0) - (b.distance || 0);
          break;
        case 'type':
          comparison = a.type.localeCompare(b.type);
          break;
        case 'name':
          comparison = a.name.localeCompare(b.name);
          break;
        case 'dish':
          comparison = a.menu[0]?.name.localeCompare(b.menu[0]?.name) || 0;
          break;
      }
      return sortOrder === 'asc' ? comparison : -comparison;
    });

  const login = (username: string, password: string) => {
    if (username && password) {
      setUser(mockUser);
      return true;
    }
    return false;
  };

  const logout = () => {
    setUser(null);
    setCurrentPage('login');
  };

  const register = (username: string, email: string, password: string) => {
    if (username && email && password) {
      setUser({ ...mockUser, username, email });
      return true;
    }
    return false;
  };

  return (
    <AppContext.Provider
      value={{
        user,
        setUser,
        isLoggedIn: !!user,
        restaurants: mockRestaurants,
        filteredRestaurants,
        filters,
        setFilters,
        viewMode,
        setViewMode,
        sortOption,
        setSortOption,
        sortOrder,
        setSortOrder,
        selectedRestaurant,
        setSelectedRestaurant,
        currentPage,
        setCurrentPage,
        login,
        logout,
        register,
      }}
    >
      {children}
    </AppContext.Provider>
  );
}

export function useApp() {
  const context = useContext(AppContext);
  if (!context) {
    throw new Error('useApp must be used within AppProvider');
  }
  return context;
}

