import { Restaurant } from '../types';
import { MapPin, Phone, ExternalLink, Info } from 'lucide-react';
import { useApp } from '../context/AppContext';

interface RestaurantCardProps {
  restaurant: Restaurant;
  onViewDetails: () => void;
}

export function RestaurantCard({ restaurant, onViewDetails }: RestaurantCardProps) {
  const { setSelectedRestaurant } = useApp();

  const handleNavigate = () => {
    const address = encodeURIComponent(restaurant.address);
    window.open(`https://www.google.com/maps/dir/?api=1&destination=${address}`, '_blank');
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
      <div className="flex gap-3 p-3">
        <img
          src={restaurant.picture}
          alt={restaurant.name}
          className="w-20 h-20 rounded-lg object-cover flex-shrink-0"
        />
        <div className="flex-1 min-w-0">
          <h3 className="font-semibold text-gray-900 truncate">{restaurant.name}</h3>
          <p className="text-xs text-gray-500">{restaurant.type}</p>
          <div className="flex items-center gap-1 mt-1 text-xs text-gray-600">
            <MapPin size={12} />
            <span>{restaurant.distance} km</span>
          </div>
          <p className="text-sm font-medium text-orange-600 mt-1">
            {restaurant.averagePrice} SEK
          </p>
        </div>
      </div>

      <div className="px-3 pb-3 flex gap-2">
        <button
          onClick={handleNavigate}
          className="flex-1 bg-orange-500 text-white text-sm font-medium py-2 px-3 rounded-lg hover:bg-orange-600 transition-colors"
        >
          Navigate
        </button>
        <a
          href={restaurant.website}
          target="_blank"
          rel="noopener noreferrer"
          className="p-2 border border-gray-200 rounded-lg hover:bg-gray-50 transition-colors"
        >
          <ExternalLink size={18} className="text-gray-600" />
        </a>
        <button
          onClick={onViewDetails}
          className="p-2 border border-gray-200 rounded-lg hover:bg-gray-50 transition-colors"
        >
          <Info size={18} className="text-gray-600" />
        </button>
      </div>
    </div>
  );
}

import { Restaurant } from '../types';
import { MapPin, Navigation } from 'lucide-react';

interface MapViewProps {
  restaurants: Restaurant[];
  onSelectRestaurant: (restaurant: Restaurant) => void;
}

export function MapView({ restaurants, onSelectRestaurant }: MapViewProps) {
  const handleNavigate = (restaurant: Restaurant) => {
    const address = encodeURIComponent(restaurant.address);
    window.open(`https://www.google.com/maps/dir/?api=1&destination=${address}`, '_blank');
  };

  return (
    <div className="relative h-full bg-gray-100">
      {/* Simulated Map Background */}
      <div className="absolute inset-0 bg-gradient-to-br from-blue-100 via-green-100 to-gray-100">
        {/* Map grid lines */}
        <div className="absolute inset-0 opacity-20">
          {[...Array(10)].map((_, i) => (
            <div key={`h-${i}`} className="absolute h-px bg-gray-400 w-full" style={{ top: `${i * 10}%` }} />
          ))}
          {[...Array(10)].map((_, i) => (
            <div key={`v-${i}`} className="absolute w-px bg-gray-400 h-full" style={{ left: `${i * 10}%` }} />
          ))}
        </div>

        {/* User location marker */}
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2">
          <div className="relative">
            <div className="w-4 h-4 bg-blue-600 rounded-full border-4 border-white shadow-lg" />
            <div className="absolute inset-0 w-4 h-4 bg-blue-600 rounded-full animate-ping opacity-75" />
          </div>
          <p className="absolute top-6 left-1/2 -translate-x-1/2 text-xs font-medium text-blue-800 whitespace-nowrap">
            You are here
          </p>
        </div>

        {/* Restaurant pins */}
        {restaurants.slice(0, 10).map((restaurant, index) => {
          const angle = (index / 10) * 2 * Math.PI;
          const radius = 20 + (index % 3) * 12;
          const x = 50 + radius * Math.cos(angle);
          const y = 50 + radius * Math.sin(angle);

          return (
            <div
              key={restaurant.id}
              className="absolute transform -translate-x-1/2 -translate-y-full cursor-pointer group"
              style={{ left: `${x}%`, top: `${y}%` }}
              onClick={() => onSelectRestaurant(restaurant)}
            >
              <div className="relative">
                <div className="w-8 h-8 bg-orange-500 rounded-full border-2 border-white shadow-lg flex items-center justify-center text-white text-xs font-bold hover:bg-orange-600 hover:scale-110 transition-all">
                  {index + 1}
                </div>
                <p className="absolute top-full left-1/2 -translate-x-1/2 mt-1 text-xs font-medium text-gray-800 bg-white px-2 py-1 rounded shadow opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap">
                  {restaurant.name}
                </p>
              </div>
            </div>
          );
        })}
      </div>

      {/* Map overlay info */}
      <div className="absolute bottom-4 left-4 right-4 bg-white rounded-xl shadow-lg p-3">
        <div className="flex items-center justify-between">
          <div>
            <p className="text-sm font-medium text-gray-900">
              {restaurants.length} restaurants found
            </p>
            <p className="text-xs text-gray-500">Tap a pin for details</p>
          </div>
          <div className="flex items-center gap-1 text-xs text-gray-600">
            <div className="w-3 h-3 bg-blue-600 rounded-full" />
            <span>Your location</span>
            <div className="w-3 h-3 bg-orange-500 rounded-full ml-2" />
            <span>Restaurants</span>
          </div>
        </div>
      </div>
    </div>
  );
}

import { useState } from 'react';
import { X, SlidersHorizontal } from 'lucide-react';
import { useApp } from '../context/AppContext';
import { restaurantTypes, dishes } from '../data';

export function FilterMenu() {
  const { filters, setFilters } = useApp();
  const [isOpen, setIsOpen] = useState(false);
  const [localFilters, setLocalFilters] = useState(filters);

  const handleApply = () => {
    setFilters(localFilters);
    setIsOpen(false);
  };

  const handleReset = () => {
    setLocalFilters({});
    setFilters({});
    setIsOpen(false);
  };

  return (
    <>
      <button
        onClick={() => setIsOpen(true)}
        className="flex items-center gap-2 px-4 py-2 bg-white border border-gray-200 rounded-lg text-sm font-medium text-gray-700 hover:bg-gray-50 transition-colors"
      >
        <SlidersHorizontal size={16} />
        Filters
        {(localFilters.priceMax || localFilters.type || localFilters.dish) && (
          <span className="w-2 h-2 bg-orange-500 rounded-full" />
        )}
      </button>

      {isOpen && (
        <div className="fixed inset-0 z-50 bg-black/50 flex items-end">
          <div className="bg-white w-full rounded-t-2xl p-4 max-h-[80vh] overflow-y-auto">
            <div className="flex items-center justify-between mb-4">
              <h2 className="text-lg font-semibold text-gray-900">Filters</h2>
              <button onClick={() => setIsOpen(false)} className="p-2 hover:bg-gray-100 rounded-lg">
                <X size={20} className="text-gray-500" />
              </button>
            </div>

            <div className="space-y-6">
              {/* Distance Filter */}
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Distance (km)
                </label>
                <div className="flex items-center gap-2">
                  <input
                    type="number"
                    placeholder="Min"
                    value={localFilters.distanceMin || ''}
                    onChange={(e) =>
                      setLocalFilters({ ...localFilters, distanceMin: Number(e.target.value) || undefined })
                    }
                    className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm"
                    min="0"
                  />
                  <span className="text-gray-400">-</span>
                  <input
                    type="number"
                    placeholder="Max"
                    value={localFilters.distanceMax || ''}
                    onChange={(e) =>
                      setLocalFilters({ ...localFilters, distanceMax: Number(e.target.value) || undefined })
                    }
                    className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm"
                    min="0"
                  />
                </div>
              </div>

              {/* Price Filter */}
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Price (SEK)
                </label>
                <div className="flex items-center gap-2">
                  <input
                    type="number"
                    placeholder="Min"
                    value={localFilters.priceMin || ''}
                    onChange={(e) =>
                      setLocalFilters({ ...localFilters, priceMin: Number(e.target.value) || undefined })
                    }
                    className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm"
                    min="0"
                  />
                  <span className="text-gray-400">-</span>
                  <input
                    type="number"
                    placeholder="Max"
                    value={localFilters.priceMax || ''}
                    onChange={(e) =>
                      setLocalFilters({ ...localFilters, priceMax: Number(e.target.value) || undefined })
                    }
                    className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm"
                    min="0"
                  />
                </div>
              </div>

              {/* Restaurant Type */}
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Restaurant Type
                </label>
                <select
                  value={localFilters.type || ''}
                  onChange={(e) =>
                    setLocalFilters({ ...localFilters, type: e.target.value || undefined })
                  }
                  className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm"
                >
                  <option value="">All types</option>
                  {restaurantTypes.map((type) => (
                    <option key={type} value={type}>
                      {type}
                    </option>
                  ))}
                </select>
              </div>

              {/* Dish */}
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Specific Dish
                </label>
                <select
                  value={localFilters.dish || ''}
                  onChange={(e) =>
                    setLocalFilters({ ...localFilters, dish: e.target.value || undefined })
                  }
                  className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm"
                >
                  <option value="">All dishes</option>
                  {dishes.map((dish) => (
                    <option key={dish} value={dish}>
                      {dish}
                    </option>
                  ))}
                </select>
              </div>
            </div>

            <div className="flex gap-3 mt-6">
              <button
                onClick={handleReset}
                className="flex-1 py-3 border border-gray-200 rounded-lg font-medium text-gray-700 hover:bg-gray-50 transition-colors"
              >
                Reset
              </button>
              <button
                onClick={handleApply}
                className="flex-1 py-3 bg-orange-500 text-white rounded-lg font-medium hover:bg-orange-600 transition-colors"
              >
                Apply Filters
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  );
}

import { ArrowUpDown, ArrowUp, ArrowDown } from 'lucide-react';
import { useApp } from '../context/AppContext';
import { SortOption } from '../types';

const sortOptions: { value: SortOption; label: string }[] = [
  { value: 'distance', label: 'Distance' },
  { value: 'price', label: 'Price' },
  { value: 'name', label: 'Name' },
  { value: 'type', label: 'Type' },
  { value: 'dish', label: 'Dish' },
];

export function SortHeader() {
  const { sortOption, setSortOption, sortOrder, setSortOrder } = useApp();

  const handleSort = (option: SortOption) => {
    if (sortOption === option) {
      setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc');
    } else {
      setSortOption(option);
      setSortOrder('asc');
    }
  };

  return (
    <div className="flex items-center gap-1 overflow-x-auto pb-2 scrollbar-hide">
      {sortOptions.map((option) => (
        <button
          key={option.value}
          onClick={() => handleSort(option.value)}
          className={`flex items-center gap-1 px-3 py-1.5 rounded-full text-xs font-medium whitespace-nowrap transition-colors ${
            sortOption === option.value
              ? 'bg-orange-100 text-orange-700'
              : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
          }`}
        >
          {option.label}
          {sortOption === option.value ? (
            sortOrder === 'asc' ? (
              <ArrowUp size={12} />
            ) : (
              <ArrowDown size={12} />
            )
          ) : (
            <ArrowUpDown size={12} />
          )}
        </button>
      ))}
    </div>
  );
}

import { useState } from 'react';
import { Eye, EyeOff, LogIn } from 'lucide-react';
import { useApp } from '../context/AppContext';

export function LoginPage() {
  const { login, register, setCurrentPage } = useApp();
  const [isRegister, setIsRegister] = useState(false);
  const [username, setUsername] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (isRegister) {
      if (register(username, email, password)) {
        setCurrentPage('search');
      } else {
        setError('Please fill in all fields');
      }
    } else {
      if (login(username, password)) {
        setCurrentPage('search');
      } else {
        setError('Invalid credentials');
      }
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-orange-500 to-orange-600 flex items-center justify-center p-4">
      <div className="w-full max-w-sm">
        <div className="text-center mb-8">
          <div className="w-16 h-16 bg-white rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-lg">
            <span className="text-orange-500 font-bold text-2xl">ALI</span>
          </div>
          <h1 className="text-2xl font-bold text-white">Amazing Lunch Indicator</h1>
          <p className="text-orange-100 mt-1">Find your perfect lunch spot</p>
        </div>

        <div className="bg-white rounded-2xl shadow-xl p-6">
          <h2 className="text-xl font-semibold text-gray-900 mb-6">
            {isRegister ? 'Create Account' : 'Welcome Back'}
          </h2>

          <form onSubmit={handleSubmit} className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                Username
              </label>
              <input
                type="text"
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                className="w-full px-4 py-3 border border-gray-200 rounded-xl focus:ring-2 focus:ring-orange-500 focus:border-transparent outline-none"
                placeholder="Enter username"
              />
            </div>

            {isRegister && (
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Email
                </label>
                <input
                  type="email"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  className="w-full px-4 py-3 border border-gray-200 rounded-xl focus:ring-2 focus:ring-orange-500 focus:border-transparent outline-none"
                  placeholder="Enter email"
                />
              </div>
            )}

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                Password
              </label>
              <div className="relative">
                <input
                  type={showPassword ? 'text' : 'password'}
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className="w-full px-4 py-3 border border-gray-200 rounded-xl focus:ring-2 focus:ring-orange-500 focus:border-transparent outline-none pr-12"
                  placeholder="Enter password"
                />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600"
                >
                  {showPassword ? <EyeOff size={20} /> : <Eye size={20} />}
                </button>
              </div>
            </div>

            {error && (
              <p className="text-sm text-red-500">{error}</p>
            )}

            <button
              type="submit"
              className="w-full py-3 bg-orange-500 text-white rounded-xl font-medium hover:bg-orange-600 transition-colors flex items-center justify-center gap-2"
            >
              <LogIn size={18} />
              {isRegister ? 'Create Account' : 'Log In'}
            </button>
          </form>

          <div className="mt-4 text-center">
            <button
              onClick={() => {
                setIsRegister(!isRegister);
                setError('');
              }}
              className="text-sm text-orange-600 hover:text-orange-700 font-medium"
            >
              {isRegister
                ? 'Already have an account? Log in'
                : "Don't have an account? Sign up"}
            </button>
          </div>

          {!isRegister && (
            <p className="mt-4 text-center">
              <button className="text-sm text-gray-500 hover:text-gray-700">
                Forgot password?
              </button>
            </p>
          )}
        </div>
      </div>
    </div>
  );
}

import { useState } from 'react';
import { Search, MapPin, DollarSign, Utensils, Soup, Globe, ArrowRight } from 'lucide-react';
import { useApp } from '../context/AppContext';
import { restaurantTypes, dishes } from '../data';

export function SearchPage() {
  const { setFilters, setCurrentPage, setViewMode, filters } = useApp();
  const [searchType, setSearchType] = useState<'price' | 'destination' | 'type' | 'dish' | 'freetext' | null>(null);
  const [priceMin, setPriceMin] = useState('');
  const [priceMax, setPriceMax] = useState('');
  const [distanceMin, setDistanceMin] = useState('');
  const [distanceMax, setDistanceMax] = useState('10');
  const [selectedType, setSelectedType] = useState('');
  const [selectedDish, setSelectedDish] = useState('');
  const [freeText, setFreeText] = useState('');

  const handleSearch = () => {
    const newFilters: typeof filters = {};

    if (searchType === 'price') {
      if (priceMin) newFilters.priceMin = Number(priceMin);
      if (priceMax) newFilters.priceMax = Number(priceMax);
      setViewMode('list');
    } else if (searchType === 'destination') {
      if (distanceMin) newFilters.distanceMin = Number(distanceMin);
      if (distanceMax) newFilters.distanceMax = Number(distanceMax);
      setViewMode('map');
    } else if (searchType === 'type') {
      if (selectedType) newFilters.type = selectedType;
      setViewMode('map');
    } else if (searchType === 'dish') {
      if (selectedDish) newFilters.dish = selectedDish;
      setViewMode('map');
    } else if (searchType === 'freetext') {
      if (freeText) newFilters.freeText = freeText;
      setViewMode('map');
    }

    setFilters(newFilters);
    setCurrentPage('list');
  };

  const searchOptions = [
    {
      id: 'price',
      icon: DollarSign,
      title: 'Search by Price',
      description: 'Find restaurants within your budget',
      color: 'bg-green-500',
    },
    {
      id: 'destination',
      icon: MapPin,
      title: 'Search by Distance',
      description: 'Find restaurants near you',
      color: 'bg-blue-500',
    },
    {
      id: 'type',
      icon: Utensils,
      title: 'Search by Type',
      description: 'Filter by cuisine category',
      color: 'bg-purple-500',
    },
    {
      id: 'dish',
      icon: Soup,
      title: 'Search by Dish',
      description: 'Find restaurants serving a specific dish',
      color: 'bg-orange-500',
    },
    {
      id: 'freetext',
      icon: Globe,
      title: 'Free Text Search',
      description: 'Search by name, address, or description',
      color: 'bg-teal-500',
    },
  ];

  return (
    <div className="p-4 space-y-6">
      <div>
        <h2 className="text-lg font-semibold text-gray-900 mb-2">What are you looking for?</h2>
        <p className="text-sm text-gray-500">Select a search option to find your perfect lunch spot</p>
      </div>

      <div className="grid gap-3">
        {searchOptions.map((option) => {
          const Icon = option.icon;
          return (
            <button
              key={option.id}
              onClick={() => setSearchType(option.id as typeof searchType)}
              className={`flex items-center gap-4 p-4 bg-white rounded-xl border-2 transition-all ${
                searchType === option.id
                  ? 'border-orange-500 shadow-md'
                  : 'border-gray-100 hover:border-gray-200'
              }`}
            >
              <div className={`w-12 h-12 ${option.color} rounded-xl flex items-center justify-center`}>
                <Icon size={24} className="text-white" />
              </div>
              <div className="flex-1 text-left">
                <h3 className="font-medium text-gray-900">{option.title}</h3>
                <p className="text-sm text-gray-500">{option.description}</p>
              </div>
              <ArrowRight size={20} className="text-gray-400" />
            </button>
          );
        })}
      </div>

      {searchType && (
        <div className="bg-white rounded-xl border-2 border-gray-100 p-4 space-y-4">
          <h3 className="font-medium text-gray-900">
            {searchType === 'price' && 'Enter price range (SEK)'}
            {searchType === 'destination' && 'Enter distance range (km)'}
            {searchType === 'type' && 'Select restaurant type'}
            {searchType === 'dish' && 'Select a dish'}
            {searchType === 'freetext' && 'Enter search text'}
          </h3>

          {searchType === 'price' && (
            <div className="flex items-center gap-2">
              <input
                type="number"
                placeholder="Min"
                value={priceMin}
                onChange={(e) => setPriceMin(e.target.value)}
                className="flex-1 px-4 py-3 border border-gray-200 rounded-xl"
                min="0"
              />
              <span className="text-gray-400">-</span>
              <input
                type="number"
                placeholder="Max"
                value={priceMax}
                onChange={(e) => setPriceMax(e.target.value)}
                className="flex-1 px-4 py-3 border border-gray-200 rounded-xl"
                min="0"
              />
            </div>
          )}

          {searchType === 'destination' && (
            <div className="flex items-center gap-2">
              <input
                type="number"
                placeholder="0"
                value={distanceMin}
                onChange={(e) => setDistanceMin(e.target.value)}
                className="flex-1 px-4 py-3 border border-gray-200 rounded-xl"
                min="0"
              />
              <span className="text-gray-400">-</span>
              <input
                type="number"
                placeholder="10"
                value={distanceMax}
                onChange={(e) => setDistanceMax(e.target.value)}
                className="flex-1 px-4 py-3 border border-gray-200 rounded-xl"
                min="0"
              />
              <span className="text-gray-500 text-sm">km</span>
            </div>
          )}

          {searchType === 'type' && (
            <select
              value={selectedType}
              onChange={(e) => setSelectedType(e.target.value)}
              className="w-full px-4 py-3 border border-gray-200 rounded-xl"
            >
              <option value="">Select type</option>
              {restaurantTypes.map((type) => (
                <option key={type} value={type}>{type}</option>
              ))}
            </select>
          )}

          {searchType === 'dish' && (
            <select
              value={selectedDish}
              onChange={(e) => setSelectedDish(e.target.value)}
              className="w-full px-4 py-3 border border-gray-200 rounded-xl"
            >
              <option value="">Select dish</option>
              {dishes.map((dish) => (
                <option key={dish} value={dish}>{dish}</option>
              ))}
            </select>
          )}

          {searchType === 'freetext' && (
            <input
              type="text"
              placeholder="Search restaurants..."
              value={freeText}
              onChange={(e) => setFreeText(e.target.value)}
              className="w-full px-4 py-3 border border-gray-200 rounded-xl"
            />
          )}

          <button
            onClick={handleSearch}
            className="w-full py-3 bg-orange-500 text-white rounded-xl font-medium hover:bg-orange-600 transition-colors flex items-center justify-center gap-2"
          >
            <Search size={18} />
            Search Restaurants
          </button>
        </div>
      )}
    </div>
  );
}

import { useApp } from '../context/AppContext';
