import { useState } from 'react';
import { User, Mail, Phone, Lock, Globe, LogOut, Save } from 'lucide-react';
import { useApp } from '../context/AppContext';
import { User as UserType } from '../types';

const languages = [
  { code: 'en', name: 'English' },
  { code: 'sv', name: 'Swedish' },
  { code: 'es', name: 'Spanish' },
  { code: 'fr', name: 'French' },
];

export function ProfilePage() {
  const { user, setUser, logout, setCurrentPage } = useApp();
  const [formData, setFormData] = useState({
    username: user?.username || '',
    email: user?.email || '',
    phone: user?.phone || '',
    password: '',
    language: user?.language || 'en',
  });
  const [isSaved, setIsSaved] = useState(false);

  const handleSave = () => {
    if (user) {
      setUser({
        ...user,
        username: formData.username,
        email: formData.email,
        phone: formData.phone,
        language: formData.language as UserType['language'],
      });
      setIsSaved(true);
      setTimeout(() => setIsSaved(false), 2000);
    }
  };

  const handleLogout = () => {
    logout();
  };

  return (
    <div className="p-4 space-y-6">
      <div className="text-center">
        <div className="w-20 h-20 bg-orange-100 rounded-full flex items-center justify-center mx-auto mb-3">
          <User size={40} className="text-orange-500" />
        </div>
        <h2 className="text-xl font-semibold text-gray-900">{user?.username}</h2>
        <p className="text-sm text-gray-500">{user?.email}</p>
      </div>

      <div className="bg-white rounded-xl border border-gray-100 divide-y divide-gray-100">
        <div className="p-4">
          <label className="flex items-center gap-3">
            <div className="w-10 h-10 bg-gray-100 rounded-lg flex items-center justify-center">
              <User size={20} className="text-gray-500" />
            </div>
            <div className="flex-1">
              <p className="text-xs text-gray-500">Username</p>
              <input
                type="text"
                value={formData.username}
                onChange={(e) => setFormData({ ...formData, username: e.target.value })}
                className="w-full text-sm font-medium text-gray-900 bg-transparent border-none outline-none p-0"
              />
            </div>
          </label>
        </div>

        <div className="p-4">
          <label className="flex items-center gap-3">
            <div className="w-10 h-10 bg-gray-100 rounded-lg flex items-center justify-center">
              <Mail size={20} className="text-gray-500" />
            </div>
            <div className="flex-1">
              <p className="text-xs text-gray-500">Email</p>
              <input
                type="email"
                value={formData.email}
                onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                className="w-full text-sm font-medium text-gray-900 bg-transparent border-none outline-none p-0"
              />
            </div>
          </label>
        </div>

        <div className="p-4">
          <label className="flex items-center gap-3">
            <div className="w-10 h-10 bg-gray-100 rounded-lg flex items-center justify-center">
              <Phone size={20} className="text-gray-500" />
            </div>
            <div className="flex-1">
              <p className="text-xs text-gray-500">Phone (optional)</p>
              <input
                type="tel"
                value={formData.phone}
                onChange={(e) => setFormData({ ...formData, phone: e.target.value })}
                className="w-full text-sm font-medium text-gray-900 bg-transparent border-none outline-none p-0"
                placeholder="Add phone number"
              />
            </div>
          </label>
        </div>

        <div className="p-4">
          <label className="flex items-center gap-3">
            <div className="w-10 h-10 bg-gray-100 rounded-lg flex items-center justify-center">
              <Lock size={20} className="text-gray-500" />
            </div>
            <div className="flex-1">
              <p className="text-xs text-gray-500">Password</p>
              <input
                type="password"
                value={formData.password}
                onChange={(e) => setFormData({ ...formData, password: e.target.value })}
                className="w-full text-sm font-medium text-gray-900 bg-transparent border-none outline-none p-0"
                placeholder="Change password"
              />
            </div>
          </label>
        </div>

        <div className="p-4">
          <label className="flex items-center gap-3">
            <div className="w-10 h-10 bg-gray-100 rounded-lg flex items-center justify-center">
              <Globe size={20} className="text-gray-500" />
            </div>
            <div className="flex-1">
              <p className="text-xs text-gray-500 mb-2">Language</p>
              <div className="flex gap-2">
                {languages.map((lang) => (
                  <button
                    key={lang.code}
                    onClick={() => setFormData({ ...formData, language: lang.code })}
                    className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-colors ${
                      formData.language === lang.code
                        ? 'bg-orange-500 text-white'
                        : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                    }`}
                  >
                    {lang.name}
                  </button>
                ))}
              </div>
            </div>
          </label>
        </div>
      </div>

      <div className="space-y-3">
        <button
          onClick={handleSave}
          className="w-full py-3 bg-orange-500 text-white rounded-xl font-medium hover:bg-orange-600 transition-colors flex items-center justify-center gap-2"
        >
          <Save size={18} />
          {isSaved ? 'Saved!' : 'Save Changes'}
        </button>

        <button
          onClick={handleLogout}
          className="w-full py-3 bg-white border border-gray-200 text-gray-700 rounded-xl font-medium hover:bg-gray-50 transition-colors flex items-center justify-center gap-2"
        >
          <LogOut size={18} />
          Log Out
        </button>
      </div>

      <p className="text-center text-xs text-gray-400">
        Amazing Lunch Indicator v1.0.0
      </p>
    </div>
  );
}

import { useState } from 'react';
import { AppProvider, useApp } from './context/AppContext';
import { Header } from './components/Header';
import { LoginPage } from './components/LoginPage';
import { SearchPage } from './components/SearchPage';
import { ListPage } from './components/ListPage';
import { MapPage } from './components/MapPage';
import { ProfilePage } from './components/ProfilePage';
import { RestaurantDetail } from './components/RestaurantDetail';
import { Restaurant } from './types';

function AppContent() {
  const { isLoggedIn, currentPage, viewMode } = useApp();
  const [selectedRestaurant, setSelectedRestaurant] = useState<Restaurant | null>(null);

  const handleViewDetails = (restaurant: Restaurant) => {
    setSelectedRestaurant(restaurant);
  };

  const handleSelectFromMap = (restaurant: Restaurant) => {
    setSelectedRestaurant(restaurant);
  };

  if (!isLoggedIn) {
    return <LoginPage />;
  }

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col max-w-md mx-auto">
      <Header />

      <main className="flex-1 flex flex-col overflow-hidden">
        {currentPage === 'search' && <SearchPage />}
        {currentPage === 'list' && <ListPage onViewDetails={handleViewDetails} />}
        {currentPage === 'map' && <MapPage onSelectRestaurant={handleSelectFromMap} />}
        {currentPage === 'profile' && <ProfilePage />}
        {currentPage === 'list' && viewMode === 'map' && <MapPage onSelectRestaurant={handleSelectFromMap} />}
      </main>

      {selectedRestaurant && (
        <RestaurantDetail
          restaurant={selectedRestaurant}
          onClose={() => setSelectedRestaurant(null)}
        />
      )}
    </div>
  );
}

export default function App() {
  return (
    <AppProvider>
      <AppContent />
    </AppProvider>
  );
}

